		t.Fatalf("unexpected timeout reason: %q", reason)
	}
	if elapsed >= 200*time.Millisecond {
		t.Fatalf("timed-out hook should return promptly, elapsed=%s", elapsed)
	}
	select {
	case <-started:
	default:
		t.Fatalf("pre-claim hook never started")
	}
}

