	runGitInteg(t, workDir, "commit", "-m", "chore: initial seed")
	runGitInteg(t, workDir, "push", "-u", "origin", "main")

	initialSHA = runGitInteg(t, workDir, "rev-parse", "HEAD")
	return workDir, originDir, initialSHA
}

