518	func waitForEmptyGitIndex(dir string, timeout time.Duration) error {
519		deadline := time.Now().Add(timeout)
520		repairedCorruptIndex := false
521		for {
522			out, err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").CombinedOutput()
523			if err == nil {
524				return nil
525			}
526			// There are staged changes (or a corrupt index). DDx-managed tracker
527			// files (.ddx/beads.jsonl, .ddx/metrics/attempts.jsonl, …) are
528			// append-mostly metadata that concurrent workers rewrite continuously;
529			// a short wait for them to settle reliably fails on a busy multi-worker
530			// host and wedges the queue (ddx-df77e668). They are not code, and the
531			// next claim rewrites them anyway, so they must never block a claim.
532			// When the only staged paths are tracker files, the landing worktree is
533			// clean for claim purposes.
534			if blocking, ok := blockingStagedPaths(dir); ok && len(blocking) == 0 {
535				return nil
536			}
537			if !repairedCorruptIndex && isRecoverableLandingIndexCorruption(string(out)) {
538				repairedCorruptIndex = true
539				if _, recErr := readTreeHeadWithRetry(dir); recErr != nil {
540					return fmt.Errorf("repairing landing worktree index: %w", recErr)
541				}
542				if err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").Run(); err == nil {
543					return nil
544				}
545			}
546			if time.Now().After(deadline) {
547				// The index drifted from HEAD. Two causes are possible:
548				//   1. A prior land's post-merge SyncWorkTreeToHead failed
549				//      (e.g. transient .git/index.lock contention) and its
550				//      error was swallowed by the best-effort caller. The
551				//      index now matches a recent ancestor of HEAD —
552				//      reverting the most recent merges. Recovering by
553				//      running read-tree HEAD is safe and unblocks the queue.
554				//   2. The operator staged real work that does not match any
555				//      ancestor tree. Recovery here would silently destroy
556				//      their changes — refuse, surface the error, and let
557				//      the operator resolve it.
558				if matches, _ := indexMatchesRecentAncestorTree(dir, 20); matches {
559					if _, recErr := readTreeHeadWithRetry(dir); recErr == nil {
560						if err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").Run(); err == nil {
561							return nil
562						}
563					}
564				}
565				stagedOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-status").CombinedOutput()
