	if err != nil {
		return false, fmt.Errorf("writing checkpoint tree: %s: %w", strings.TrimSpace(string(treeOut)), err)
	}
	tree := strings.TrimSpace(string(treeOut))
	msg := "chore: checkpoint pre-execute-bead " + attemptID
